import asyncio
import websockets
from collections import defaultdict

class Inventory:
    def __init__(self):
        self.items = defaultdict(int)

    async def add_item(self, player_id, item_id, quantity):
        self.items[player_id][item_id] += quantity
        await self.update_inventory(player_id)

    async def remove_item(self, player_id, item_id, quantity):
        if self.items[player_id][item_id] >= quantity:
            self.items[player_id][item_id] -= quantity
            await self.update_inventory(player_id)
        else:
            raise ValueError("Not enough items to remove")

    async def update_inventory(self, player_id):
        # Simulate sending updated inventory to the player
        print(f"Player {player_id} inventory updated: {self.items[player_id]}")

async def trade_items(websocket, path):
    async for message in websocket:
        data = eval(message)
        if data['action'] == 'trade':
            sender_id = data['sender']
            receiver_id = data['receiver']
            item_id = data['item_id']
            quantity = data['quantity']

            sender_inventory = Inventory()
            receiver_inventory = Inventory()

            try:
                await sender_inventory.remove_item(sender_id, item_id, quantity)
                await receiver_inventory.add_item(receiver_id, item_id, quantity)
                print(f"Trade successful: {sender_id} gave {quantity} {item_id} to {receiver_id}")
            except ValueError as e:
                await websocket.send(str(e))

start_server = websockets.serve(trade_items, "localhost", 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()